size_type query(Predicates const& predicates, OutIter out_it) const
{
    if ( !m_members.root )
        return 0;

    static const unsigned distance_predicates_count = detail::predicates_count_distance<Predicates>::value;
    static const bool is_distance_predicate = 0 < distance_predicates_count;
    BOOST_MPL_ASSERT_MSG((distance_predicates_count <= 1), PASS_ONLY_ONE_DISTANCE_PREDICATE, (Predicates));

    return query_dispatch(predicates, out_it, boost::mpl::bool_<is_distance_predicate>());
}

size_type query_dispatch(Predicates const& predicates, OutIter out_it, boost::mpl::bool_<true> const& /*is_distance_predicate*/) const
{
    BOOST_GEOMETRY_INDEX_ASSERT(m_members.root, "The root must exist");

    static const unsigned distance_predicate_index = detail::predicates_find_distance<Predicates>::value;
    detail::rtree::visitors::distance_query<
        members_holder,
        Predicates,
        distance_predicate_index,
        OutIter
    > distance_v(m_members.parameters(), m_members.translator(), predicates, out_it);

    detail::rtree::apply_visitor(distance_v, *m_members.root);

    return distance_v.finish();
}

inline void apply_visitor(Visitor & visitor) const
{
    if ( m_members.root )
        detail::rtree::apply_visitor(visitor, *m_members.root);
}

inline InverseCovariance2D precomputeInverseCovarianceFromPose(
  const std::array<double, 36> & pose_covariance)
{
  // Step 1: Extract a, b, d directly from pose_covariance (no temporary Matrix2d)
  constexpr double minimum_cov = 0.25;  // 0.5 m to avoid too large mahalanobis distance
  const double a = std::max(pose_covariance[0], minimum_cov);  // cov(0,0)
  const double b = pose_covariance[1];  // cov(0,1) == pose_covariance[6] (symmetry)
  const double d = std::max(pose_covariance[7], minimum_cov);  // cov(1,1)

  // Step 2: Compute determinant and inverse components in one pass
  const double det = a * d - b * b;
  const double inv_det = 1.0 / det;

  InverseCovariance2D result;
  result.inv00 = d * inv_det;   // d / det
  result.inv01 = -b * inv_det;  // -b / det
  result.inv11 = a * inv_det;   // a / det
  return result;
}

double DataAssociation::calculateScore(
  const types::DynamicObject & tracked_object, const std::uint8_t tracker_label,
  const types::DynamicObject & measurement_object, const std::uint8_t measurement_label,
  const InverseCovariance2D & inv_cov, bool & has_significant_shape_change) const
{
  // when the tracker and measurements are unknown, use generalized IoU
  if (tracker_label == Label::UNKNOWN && measurement_label == Label::UNKNOWN) {
    const double & generalized_iou_threshold = config_.unknown_association_giou_threshold;
    const double generalized_iou = shapes::get2dGeneralizedIoU(tracked_object, measurement_object);
    if (generalized_iou < generalized_iou_threshold) {
      return INVALID_SCORE;
    }
    // rescale score to [0, 1]
    return (generalized_iou - generalized_iou_threshold) / (1.0 - generalized_iou_threshold);
  }

  const double max_dist_sq = config_.max_dist_matrix(tracker_label, measurement_label);
  const double dx = measurement_object.pose.position.x - tracked_object.pose.position.x;
  const double dy = measurement_object.pose.position.y - tracked_object.pose.position.y;
  const double dist_sq = dx * dx + dy * dy;

  // dist gate
  if (dist_sq > max_dist_sq) return INVALID_SCORE;

  // gates for non-vehicle objects
  const double area_meas = measurement_object.area;
  const bool is_vehicle_tracker = tracker_label == Label::CAR || tracker_label == Label::BUS ||
                                  tracker_label == Label::TRUCK || tracker_label == Label::TRAILER;
  if (!is_vehicle_tracker) {
    // area gate
    const double max_area = config_.max_area_matrix(tracker_label, measurement_label);
    const double min_area = config_.min_area_matrix(tracker_label, measurement_label);
    if (area_meas < min_area || area_meas > max_area) return INVALID_SCORE;

    // mahalanobis dist gate
    const double mahalanobis_dist = getMahalanobisDistanceFast(dx, dy, inv_cov);

    constexpr double mahalanobis_dist_threshold =
      11.62;  // This is an empirical value corresponding to the 99.6% confidence level
              // for a chi-square distribution with 2 degrees of freedom (critical value).

    if (mahalanobis_dist >= mahalanobis_dist_threshold) return INVALID_SCORE;
  }

  const double min_iou = config_.min_iou_matrix(tracker_label, measurement_label);

  // use 1d iou for pedestrian, 3d giou for other objects if both extensions are trustable
  // otherwise use 2d giou
  const bool use_1d_iou = (tracker_label == Label::PEDESTRIAN);
  const bool use_3d_iou = (tracked_object.trust_extension) && (measurement_object.trust_extension);

  double iou_score;
  if (use_1d_iou) {
    iou_score = shapes::get1dIoU(measurement_object, tracked_object);
  } else if (use_3d_iou) {
    iou_score = shapes::get3dGeneralizedIoU(measurement_object, tracked_object);
  } else {
    iou_score = shapes::get2dGeneralizedIoU(measurement_object, tracked_object);
  }
  if (iou_score < min_iou) return INVALID_SCORE;

  // check if shape changes too much for vehicle labels
  if (iou_score < CHECK_GIOU_THRESHOLD && is_vehicle_tracker) {
    // BEV‑area ratio
    const double area_trk = tracked_object.area;
    const double area_ratio = std::max(area_trk, area_meas) / std::min(area_trk, area_meas);

    if (area_ratio > AREA_RATIO_THRESHOLD) {
      has_significant_shape_change = true;
    }
  }

  // rescale score to [0, 1]
  return (iou_score - min_iou) / (1.0 - min_iou);
}

double get2dGeneralizedIoU(
  const types::DynamicObject & source_object, const types::DynamicObject & target_object)
{
  static const double MIN_AREA = 1e-6;

  const auto source_polygon =
    autoware_utils_geometry::to_polygon2d(source_object.pose, source_object.shape);
  const double source_area = boost::geometry::area(source_polygon);
  const auto target_polygon =
    autoware_utils_geometry::to_polygon2d(target_object.pose, target_object.shape);
  const double target_area = boost::geometry::area(target_polygon);
  if (source_area < MIN_AREA && target_area < MIN_AREA) return -1.0;

  const double intersection_area = getIntersectionArea(source_polygon, target_polygon);
  const double union_area = getUnionArea(source_polygon, target_polygon);
  const double iou = union_area < 0.01 ? 0.0 : std::min(1.0, intersection_area / union_area);
  const double convex_shape_area = getConvexShapeArea(source_polygon, target_polygon);

  return iou - (convex_shape_area - union_area) / convex_shape_area;
}

Polygon2d to_polygon2d(
  const geometry_msgs::msg::Pose & pose, const autoware_perception_msgs::msg::Shape & shape)
{
  Polygon2d polygon;

  if (shape.type == autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    const auto point0 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point1 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point2 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point3 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;

    append_point_to_polygon(polygon, point0);
    append_point_to_polygon(polygon, point1);
    append_point_to_polygon(polygon, point2);
    append_point_to_polygon(polygon, point3);
  } else if (shape.type == autoware_perception_msgs::msg::Shape::CYLINDER) {
    const double radius = shape.dimensions.x / 2.0;
    constexpr int circle_discrete_num = 6;
    for (int i = 0; i < circle_discrete_num; ++i) {
      geometry_msgs::msg::Point point;
      point.x = std::cos(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.x;
      point.y = std::sin(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.y;
      append_point_to_polygon(polygon, point);
    }
  } else if (shape.type == autoware_perception_msgs::msg::Shape::POLYGON) {
    const double poly_yaw = tf2::getYaw(pose.orientation);
    const auto rotated_footprint = rotate_polygon(shape.footprint, poly_yaw);
    for (const auto rel_point : rotated_footprint.points) {
      geometry_msgs::msg::Point abs_point;
      abs_point.x = pose.position.x + rel_point.x;
      abs_point.y = pose.position.y + rel_point.y;

      append_point_to_polygon(polygon, abs_point);
    }
  } else {
    throw std::logic_error("The shape type is not supported in autoware_utils.");
  }

  // NOTE: push back the first point in order to close polygon
  if (!polygon.outer().empty()) {
    append_point_to_polygon(polygon, polygon.outer().front());
  }

  return is_clockwise(polygon) ? polygon : inverse_clockwise(polygon);
}

